def assess(record: dict) -> str:
    required = {"case_id", "method", "resource", "created", "status"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["method"] == "POST" and record["status"] == 201) else "RETURN_CORRECT_HTTP_STATUS"

valid = {"case_id": "CASO-ARE-041-1A", **{"method": "POST", "resource": "/v1/jobs", "created": True, "status": 201}}
invalid = {"case_id": "CASO-ARE-041-1A", **{"method": "", "resource": "/v1/jobs", "created": True, "status": 201}}
incomplete = {**valid}
incomplete.pop("status", None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

